//   requires ValidPath(path)
//   requires pos <= |path|
//   requires pos == 0 ==> |acc| == 0
//   requires pos == 1 ==> acc == CanonicalPart(path[0])
//   requires acc == MakeCanonicalPathGhost(path[..pos])
//   ensures |path| == 0 && pos == 0 ==> ret == []
//   ensures |path| == 1 ==> ret == CanonicalPart(path[0])
