      byte[] keyBytes = new byte[keyLen]; buf.get(keyBytes);
      byte[] valTypeId = new byte[2]; buf.get(valTypeId);
      int valLen = buf.getInt();
      byte[] valBytes = new byte[valLen]; buf.get(valBytes);
